 {% if s.pseudo_kind == 'choice' %}
 state {{ s.id }} <<choice>>
 {% elif s.pseudo_kind == 'junction' %}
 state {{ s.id }} <<junction>>
 {% elif s.pseudo_kind == 'shallowHistory' %}
 state {{ s.id }} <<history>>
 {% elif s.pseudo_kind == 'deepHistory' %}
 state {{ s.id }} <<history*>>
 {% elif s.pseudo_kind not in ('initial', 'final') %}
 state "{{ s.title }}" as {{ s.id }} [[{{ ref(s.id) }}]]
 {% endif %}
