 {% if t.guard %}{% set label = label + ' [' + t.guard + ']' %}{% endif %}
 {% if t.effect %}{% set label = label + ' / ' + t.effect %}{% endif %}
 {{ src_render }} --> {{ dst_render }}{% if label %} : {{ label }}{% endif %}

 {% endif %}
 {% endfor %}
 @enduml
 """


