 {% for a in actions %}
 {% set part = a.partition or '_default' %}
 {% if part not in partition_names %}{% set _ = partition_names.append(part) %}{% endif %}
 {% endfor %}
 {% set lane_w = 200 %}
 {% set lane_h = 80 %}
