            # Check for plantuml image
            if 'plantuml' in section.lower():
                match = re.search(r'src=\"([^\"]*plantuml[^\"]*\\.svg)\"', section)
                if match:
                    print('SVG:', match.group(1))
    else:
        print('Section heading not found')
else:
    print('Heading not found')
"

